const uaContent = $node["Groq_Write_UA"].json.choices[0].message.content;
const enContent = $node["Groq_Translate_EN"].json.choices[0].message.content;
const selection = JSON.parse($node["Groq_Pick_Topic"].json.choices[0].message.content);

// Bulletproof slug sanitizer — strips spaces, $, and any special chars
const rawSlug = (selection.slug || 'ai-post').toLowerCase();
const slug = rawSlug.replace(/[^a-z0-9-]/g, '-').replace(/--+/g, '-').replace(/^-|-$/g, '');

const now = new Date().toISOString().split('T')[0];
const clean = (txt) => txt.replace(/^[ \t]+/gm, '').trim();

const createMD = (title, content, excerpt) => `--- \ntitle: "${title}"\ndate: "${now}"\nupdated: "${now}"\nexcerpt: "${excerpt}"\ncategory: "Autonomous Business"\ntags: ["AI-Agents", "Automation", "Vision"]\nfeatured: false\nimage: ""\n---\n\n${clean(content)}`;

return {
  ua: { path: `content/posts/${slug}.md`, content: createMD(selection.title_ua, uaContent, "Аналіз автономних систем та агентної революції.") },
  en: { path: `content/posts/en/${slug}.md`, content: createMD(selection.title_en, enContent, "Analysis of autonomous systems and the agentic revolution.") },
  topic: selection.title_ua
};
